import React from "react";
import classes from './404.module.css';
import Navbar from "../Nav/Navbar";
import NavContainer from "../Nav/NavContainer";
import {NavLink} from "react-router-dom";
import notfound from '../img/notfound.png'


const Error = (props) => {
    return <div className={classes.error}>
        <div className={classes.text404}>404</div>
        <div>LOOKS LIKE YOU'RE LOST AT SEA</div>
       <div>
           <NavLink to='/profile' className={classes.headerText}>You can go back to the profile page. </NavLink>
       </div>
        <div > <img className={classes.ship} src={notfound}/> </div>
    </div>
   }

export default Error;
